LIBRARY ieee;
USE ieee.std_logic_1164.all;

entity MUX_GATE_BUS_1 is
  generic ( Bits : integer ); 
  port (
    p_out: out std_logic_vector ((Bits-1) downto 0);
    sel: in std_logic;
    
    in_0: in std_logic_vector ((Bits-1) downto 0);
    in_1: in std_logic_vector ((Bits-1) downto 0) );
end MUX_GATE_BUS_1;

architecture Behavioral of MUX_GATE_BUS_1 is
begin
  with sel select
    p_out <=
      in_0 when '0',
      in_1 when '1',
      (others => '0') when others;
end Behavioral;


LIBRARY ieee;
USE ieee.std_logic_1164.all;
USE ieee.numeric_std.all;

entity DEMUX_GATE_BUS_2 is
  generic (
    Bits : integer;
    Default : integer );
  port (
    out_0: out std_logic_vector ((Bits-1) downto 0);
    out_1: out std_logic_vector ((Bits-1) downto 0);
    out_2: out std_logic_vector ((Bits-1) downto 0);
    out_3: out std_logic_vector ((Bits-1) downto 0);
    sel: in std_logic_vector (1 downto 0);
    p_in: in std_logic_vector ((Bits-1) downto 0) );
end DEMUX_GATE_BUS_2;

architecture Behavioral of DEMUX_GATE_BUS_2 is
begin
    out_0 <= p_in when sel = "00" else std_logic_vector(to_unsigned(Default, Bits));
    out_1 <= p_in when sel = "01" else std_logic_vector(to_unsigned(Default, Bits));
    out_2 <= p_in when sel = "10" else std_logic_vector(to_unsigned(Default, Bits));
    out_3 <= p_in when sel = "11" else std_logic_vector(to_unsigned(Default, Bits));
end Behavioral;


