entity RegisterFile is
  port (
    clk: in std_logic;
    Read_Register1: in std_logic_vector(1 downto 0);
    Read_Register2: in std_logic_vector(1 downto 0);
    Write_data: in std_logic_vector(7 downto 0);
    Write_Register: in std_logic_vector(1 downto 0);
    ctrl: in std_logic_vector(7 downto 0);
    Read_Data1: out std_logic_vector(7 downto 0);
    Read_Data2: out std_logic_vector(7 downto 0));
end RegisterFile;

architecture Behavioral of RegisterFile is
  signal s0: std_logic_vector(7 downto 0);
  signal s1: std_logic_vector(1 downto 0);
  signal s2: std_logic_vector(7 downto 0);
  signal s3: std_logic_vector(7 downto 0);
  signal s4: std_logic_vector(1 downto 0);
  signal s5: std_logic_vector(7 downto 0);
  signal s6: std_logic_vector(7 downto 0);
  signal s7: std_logic_vector(1 downto 0);
  signal s8: std_logic_vector(7 downto 0);
  signal s9: std_logic_vector(7 downto 0);
  signal s10: std_logic_vector(1 downto 0);
  signal s11: std_logic_vector(7 downto 0);
begin
  gate0: entity work.DEMUX_GATE_BUS_2
    generic map (
      Bits => 8,
      Default => 0)
    port map (
      sel => Write_Register,
      p_in => Write_data,
      out_0 => s0,
      out_1 => s3,
      out_2 => s6,
      out_3 => s9);
  s1 <= ctrl(1 downto 0);
  s4 <= ctrl(3 downto 2);
  s7 <= ctrl(5 downto 4);
  s10 <= ctrl(7 downto 6);
  gate1: entity work.n8_bit -- R0
    port map (
      CLK => clk,
      Input => s0,
      CTRL => s1,
      Output => s2);
  gate2: entity work.n8_bit -- R1
    port map (
      CLK => clk,
      Input => s3,
      CTRL => s4,
      Output => s5);
  gate3: entity work.n8_bit -- R2
    port map (
      CLK => clk,
      Input => s6,
      CTRL => s7,
      Output => s8);
  gate4: entity work.n8_bit -- R3
    port map (
      CLK => clk,
      Input => s9,
      CTRL => s10,
      Output => s11);
  gate5: entity work.MUX_GATE_BUS_2
    generic map (
      Bits => 8)
    port map (
      sel => Read_Register1,
      in_0 => s2,
      in_1 => s5,
      in_2 => s8,
      in_3 => s11,
      p_out => Read_Data1);
  gate6: entity work.MUX_GATE_BUS_2
    generic map (
      Bits => 8)
    port map (
      sel => Read_Register2,
      in_0 => s2,
      in_1 => s5,
      in_2 => s8,
      in_3 => s11,
      p_out => Read_Data2);
end Behavioral;

LIBRARY ieee;
