entity n8bitAdder2026 is
  port (
    A: in std_logic_vector(7 downto 0);
    Y: in std_logic_vector(7 downto 0);
    Carry_in: in std_logic;
    Carry_out: out std_logic;
    Sum: out std_logic_vector(7 downto 0));
end n8bitAdder2026;

architecture Behavioral of n8bitAdder2026 is
  signal s0: std_logic;
  signal s1: std_logic;
  signal s2: std_logic;
  signal s3: std_logic;
  signal s4: std_logic;
  signal s5: std_logic;
  signal s6: std_logic;
  signal s7: std_logic;
  signal s8: std_logic;
  signal s9: std_logic;
  signal s10: std_logic;
  signal s11: std_logic;
  signal s12: std_logic;
  signal s13: std_logic;
  signal s14: std_logic;
  signal s15: std_logic;
  signal s16: std_logic;
  signal s17: std_logic;
  signal s18: std_logic;
  signal s19: std_logic;
  signal s20: std_logic;
  signal s21: std_logic;
  signal s22: std_logic;
  signal s23: std_logic;
  signal s24: std_logic;
  signal s25: std_logic;
  signal s26: std_logic;
  signal s27: std_logic;
  signal s28: std_logic;
  signal s29: std_logic;
  signal s30: std_logic;
begin
  s17 <= A(0);
  s13 <= A(1);
  s9 <= A(2);
  s5 <= A(3);
  s0 <= A(4);
  s28 <= A(5);
  s24 <= A(6);
  s20 <= A(7);
  s18 <= Y(0);
  s14 <= Y(1);
  s10 <= Y(2);
  s6 <= Y(3);
  s1 <= Y(4);
  s29 <= Y(5);
  s25 <= Y(6);
  s21 <= Y(7);
  gate0: entity work.n1_bit_full_adder
    port map (
      A => s17,
      B => s18,
      C => Carry_in,
      sum => s19,
      Carry_out => s15);
  gate1: entity work.n1_bit_full_adder
    port map (
      A => s13,
      B => s14,
      C => s15,
      sum => s16,
      Carry_out => s11);
  gate2: entity work.n1_bit_full_adder
    port map (
      A => s9,
      B => s10,
      C => s11,
      sum => s12,
      Carry_out => s7);
  gate3: entity work.n1_bit_full_adder
    port map (
      A => s5,
      B => s6,
      C => s7,
      sum => s8,
      Carry_out => s2);
  gate4: entity work.n1_bit_full_adder
    port map (
      A => s0,
      B => s1,
      C => s2,
      sum => s3,
      Carry_out => s4);
  gate5: entity work.n1_bit_full_adder
    port map (
      A => s28,
      B => s29,
      C => s4,
      sum => s30,
      Carry_out => s26);
  gate6: entity work.n1_bit_full_adder
    port map (
      A => s24,
      B => s25,
      C => s26,
      sum => s27,
      Carry_out => s22);
  gate7: entity work.n1_bit_full_adder
    port map (
      A => s20,
      B => s21,
      C => s22,
      sum => s23,
      Carry_out => Carry_out);
  Sum(0) <= s19;
  Sum(1) <= s16;
  Sum(2) <= s12;
  Sum(3) <= s8;
  Sum(4) <= s3;
  Sum(5) <= s30;
  Sum(6) <= s27;
  Sum(7) <= s23;
end Behavioral;

LIBRARY ieee;
USE ieee.std_logic_1164.all;
USE ieee.numeric_std.all;

entity n8bitALU is
  port (
    A: in std_logic_vector(7 downto 0);
    S_1_S_0_Carry_in: in std_logic_vector(2 downto 0);
    B: in std_logic_vector(7 downto 0);
    Output: out std_logic_vector(7 downto 0);
    Status: out std_logic);
end n8bitALU;

architecture Behavioral of n8bitALU is
  signal s0: std_logic_vector(7 downto 0);
  signal s1: std_logic;
  signal s2: std_logic_vector(1 downto 0);
  signal s3: std_logic_vector(7 downto 0);
  signal const8b0: std_logic_vector(7 downto 0);
  signal s4: std_logic_vector(7 downto 0);
begin
  const8b0 <= "00000000";
  s3 <= NOT B;
  s4 <= NOT const8b0;
  s1 <= S_1_S_0_Carry_in(0);
  s2 <= S_1_S_0_Carry_in(2 downto 1);
  gate0: entity work.MUX_GATE_BUS_2
    generic map (
      Bits => 8)
    port map (
      sel => s2,
      in_0 => B,
      in_1 => s3,
      in_2 => const8b0,
      in_3 => s4,
      p_out => s0);
  gate1: entity work.n8bitAdder2026
    port map (
      A => A,
      Y => s0,
      Carry_in => s1,
      Carry_out => Status,
      Sum => Output);
end Behavioral;

LIBRARY ieee;
USE ieee.std_logic_1164.all;
USE ieee.numeric_std.all;

entity main is
  port (
    clk: in std_logic;
    InstrMem_input: in std_logic_vector(7 downto 0);
    InstrMem_ctrl: in std_logic_vector(1 downto 0);
    IR_output: out std_logic_vector(7 downto 0);
    Inst_Fetch: out std_logic;
    Inst_decode: out std_logic;
    Inst_exec: out std_logic;
    Write_Back: out std_logic;
    Program_Counter: out std_logic_vector(2 downto 0);
    IR_ctrl: out std_logic_vector(1 downto 0);
    RegFile_ctrl: out std_logic_vector(7 downto 0);
    ALU_output: out std_logic_vector(7 downto 0));
end main;

architecture Behavioral of main is
  signal s0: std_logic_vector(1 downto 0);
  signal s1: std_logic_vector(1 downto 0);
  signal ALU_output_temp: std_logic_vector(7 downto 0);
  signal RegFile_ctrl_temp: std_logic_vector(7 downto 0);
  signal s2: std_logic_vector(7 downto 0);
  signal s3: std_logic_vector(7 downto 0);
  signal s4: std_logic_vector(7 downto 0);
  signal s5: std_logic_vector(2 downto 0);
  signal Program_Counter_temp: std_logic_vector(2 downto 0);
  signal s6: std_logic_vector(7 downto 0);
  signal s7: std_logic_vector(1 downto 0);
  signal s8: std_logic_vector(7 downto 0);
  signal IR_ctrl_temp: std_logic_vector(1 downto 0);
  signal IR_output_temp: std_logic_vector(7 downto 0);
  signal s9: std_logic;
  signal Inst_Fetch_temp: std_logic;
  signal Write_Back_temp: std_logic;
  signal s10: std_logic;
  signal s11: std_logic_vector(7 downto 0);
  signal s12: std_logic_vector(7 downto 0);
  signal s13: std_logic;
begin
  gate0: entity work.ControlUnit
    port map (
      clk => clk,
      Inst_Fetch => Inst_Fetch_temp,
      Inst_Decode => Inst_decode,
      Inst_Execute => Inst_exec,
      Write_back => Write_Back_temp);
  s13 <= InstrMem_ctrl(0);
  s7(0) <= Write_Back_temp;
  s7(1) <= '0';
  gate1: entity work.MUX_GATE_1
    port map (
      sel => s13,
      in_0 => Inst_Fetch_temp,
      in_1 => '0',
      p_out => s10);
  gate2: entity work.n8bit_PC
    port map (
      CLK => clk,
      Inc_by => "00000001",
      CTRL => s7,
      Output => s8);
  IR_ctrl_temp(0) <= s10;
  IR_ctrl_temp(1) <= '0';
  Program_Counter_temp <= s8(2 downto 0);
  gate3: entity work.n8B_Memory
    port map (
      Address_pin => Program_Counter_temp,
      clk => clk,
      Data_input => InstrMem_input,
      CTRL => InstrMem_ctrl,
      Data_output => s6);
  gate4: entity work.n8_bit_IR
    port map (
      CLK => clk,
      Input => s6,
      CTRL => IR_ctrl_temp,
      Output => IR_output_temp);
  s9 <= IR_output_temp(0);
  s1 <= IR_output_temp(2 downto 1);
  s0 <= IR_output_temp(4 downto 3);
  s5 <= IR_output_temp(7 downto 5);
  gate5: entity work.MUX_GATE_BUS_2
    generic map (
      Bits => 8)
    port map (
      sel => s0,
      in_0 => "00000001",
      in_1 => "00000100",
      in_2 => "00010000",
      in_3 => "01000000",
      p_out => s11);
  s12(1 downto 0) <= s1;
  s12(7 downto 2) <= "000000";
  gate6: entity work.MUX_GATE_BUS_1
    generic map (
      Bits => 8)
    port map (
      sel => Write_Back_temp,
      in_0 => "00000000",
      in_1 => s11,
      p_out => RegFile_ctrl_temp);
  gate7: entity work.RegisterFile
    port map (
      clk => clk,
      Read_Register1 => s0,
      Read_Register2 => s1,
      Write_data => ALU_output_temp,
      Write_Register => s0,
      ctrl => RegFile_ctrl_temp,
      Read_Data1 => s2,
      Read_Data2 => s3);
  gate8: entity work.n8bitALU
    port map (
      A => s4,
      S_1_S_0_Carry_in => s5,
      B => s3,
      Output => ALU_output_temp);
  gate9: entity work.MUX_GATE_BUS_1
    generic map (
      Bits => 8)
    port map (
      sel => s9,
      in_0 => s2,
      in_1 => s12,
      p_out => s4);
  IR_output <= IR_output_temp;
  Inst_Fetch <= Inst_Fetch_temp;
  Write_Back <= Write_Back_temp;
  Program_Counter <= Program_Counter_temp;
  IR_ctrl <= IR_ctrl_temp;
  RegFile_ctrl <= RegFile_ctrl_temp;
  ALU_output <= ALU_output_temp;
end Behavioral;
